import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import Card from '../components/common/Card';
import DataTable from '../components/data/DataTable';
import DataToolbar from '../components/data/DataToolbar';

const mockData = {
  columns: ['Transaction ID', 'Amount', 'Timestamp', 'Risk Score'],
  rows: [
    ['txn-001', 150.00, new Date().toISOString(), 0.1],
    ['txn-002', 3200.50, new Date().toISOString(), 0.8],
    ['txn-003', 45.99, new Date().toISOString(), 0.05],
    ['txn-004', 12000.00, new Date().toISOString(), 0.95],
  ],
};

const WorkflowStage = ({ name, status, isCurrent }) => (
  <div className={`flex items-center p-2 rounded-lg ${isCurrent ? 'bg-blue-100' : 'bg-gray-50'}`}>
    <div className={`w-3 h-3 rounded-full mr-3 ${status === 'completed' ? 'bg-green-500' : (isCurrent ? 'bg-blue-500' : 'bg-gray-300')}`}></div>
    <span className={`font-medium ${isCurrent ? 'text-blue-700' : 'text-gray-600'}`}>{name}</span>
  </div>
)

function DataPreparation() {
  const [data, setData] = useState(mockData);
  const [currentStage, setCurrentStage] = useState('upload');

  const handleUpload = (uploadedData) => {
    setData(uploadedData);
    setCurrentStage('profile'); // Mock progression
  };

  const handleSolverSelect = (solver) => {
    console.log('Selected solver:', solver);
    setCurrentStage('map'); // Mock progression
  };

  return (
    <div>
      <div className="p-4 bg-gray-100 rounded-t-lg border-b mb-4">
        <h2 className="text-xl font-bold">AI Guided Analysis: Data Preparation</h2>
        <p className="text-sm text-gray-600">Session ID: session-xyz-789 (This should be dynamic)</p>
      </div>
      <div className="grid grid-cols-12 gap-8">
        <div className="col-span-3">
            <Card>
                <h3 className="text-lg font-semibold mb-4">Workflow Stages</h3>
                <div className="space-y-2">
                    <WorkflowStage name="Upload Data" status={currentStage !== 'upload' ? 'completed' : 'current'} isCurrent={currentStage === 'upload'} />
                    <WorkflowStage name="Profile Data" status={currentStage === 'map' || currentStage === 'validate' || currentStage === 'approve' ? 'completed' : 'pending'} isCurrent={currentStage === 'profile'} />
                    <WorkflowStage name="Select Solver" status={currentStage === 'validate' || currentStage === 'approve' ? 'completed' : 'pending'} isCurrent={currentStage === 'map'} />
                    <WorkflowStage name="Map Fields" status={currentStage === 'approve' ? 'completed' : 'pending'} isCurrent={currentStage === 'validate'} />
                    <WorkflowStage name="Validate & Approve" status='pending' isCurrent={currentStage === 'approve'} />
                </div>
            </Card>
        </div>
        <div className="col-span-9">
          <Card>
            <DataToolbar onUpload={handleUpload} onSolverSelect={handleSolverSelect} />
            <DataTable data={data} />
             <div className="mt-6 text-right">
                <Link to="/config" className="bg-blue-500 text-white font-bold py-2 px-4 rounded hover:bg-blue-600">
                    Proceed to Job Configuration &rarr;
                </Link>
            </div>
          </Card>
        </div>
      </div>
    </div>
  );
}

export default DataPreparation;
